   356→inline at::MemoryFormat miopen_conv_suggest_memory_format(const at::Tensor& input, const at::Tensor& weight) {
   357→  // disable NHWC for float64 input.
   358→  if (!at::detail::getCUDAHooks().compiledWithMIOpen() ||
   359→      input.scalar_type() == at::kDouble ||
   360→      weight.scalar_type() == at::kDouble) {
   361→    return at::MemoryFormat::Contiguous;
   362→  }
   363→
   364→  // TODO: Remove PYTORCH_MIOPEN_SUGGEST_NHWC once ROCm officially supports NHWC in MIOpen
   365→  // See https://github.com/pytorch/pytorch/issues/64427.
   366→  // non static variable is used to be able to change environment variable in runtime for testing
   367→  // enabled by default for ROCm >= 7.0.0 with miopen 3.5
   368→  int miopen_version = detail::getCUDAHooks().compiledWithMIOpen() ? detail::getCUDAHooks().versionMIOpen() : 0;
   369→  bool is_miopen_3_5 = miopen_version >= 30500;  // ROCm 7.0
   370→  bool suggest_nhwc = c10::utils::check_env("PYTORCH_MIOPEN_SUGGEST_NHWC").value_or(is_miopen_3_5);
   371→
   372→  auto input_memory_format = input.suggest_memory_format();
   373→  auto weight_memory_format = weight.suggest_memory_format();
   374→  auto weight_ndim = weight.ndimension();
   375→
   376→  bool can_use_miopen_channels_last_2d = suggest_nhwc && (weight_ndim == 4) && (
   377→    (input_memory_format  == at::MemoryFormat::ChannelsLast) ||
   378→    (weight_memory_format == at::MemoryFormat::ChannelsLast)
   379→  );
   380→  if (can_use_miopen_channels_last_2d) {
   381→    return at::MemoryFormat::ChannelsLast;
   382→  }
   383→
   384→  bool can_use_miopen_channels_last_3d = suggest_nhwc && (weight_ndim == 5) && (
   385→    (input_memory_format  == at::MemoryFormat::ChannelsLast3d) ||
   386→    (weight_memory_format == at::MemoryFormat::ChannelsLast3d)
   387→  );
   388→  if (can_use_miopen_channels_last_3d) {
   389→    return at::MemoryFormat::ChannelsLast3d;
   390→  }
   391→
   392→  return at::MemoryFormat::Contiguous;
   393→}
